const Q_BIOLOGY_2011=[{"id": "objective>Biology>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What subject are you currently doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Physics </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Biology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">History</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject currently being done is Biology. This is evident from the context of the question and the fact that all the questions are related to Biology.</div>", "topic": "LIVING ORGANISMS : CHARACTERISTICS"}, {"id": "objective>Biology>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The function of the red head in male Agama lizards is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conceal and camouflage the animal from predators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scare other males from the territory</div>", "<div style=\"font-family:Cambria;font-size:17px;\">attract female lizards for mating purposes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">warn predators of the distastefulness</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The red head in male Agama lizards is a form of sexual selection, used to attract females for mating.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following species is the biomass of an individual the smallest?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tilapia sp.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agama sp.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bufa sp. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra sp.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spirogyra sp. is a type of green algae, which are generally much smaller and lighter than animals like Tilapia, Agama, and Bufo.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Seed plants are divided into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tracheophytes and ferns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">angiosperms and gymnosperms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monocotyledons and dicotyledons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thallophytes and bryophytes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Seed plants are divided into angiosperms and gymnosperms. Angiosperms are flowering plants, while gymnosperms include conifers, cycads, Ginkgo, and gnetophytes.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : PLANTAE"}, {"id": "objective>Biology>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following groups of vertebrates is parental care mostly exhibited?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Reptilia </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Amphibia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aves </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mammalia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parental care is most commonly exhibited in the Mammalia group of vertebrates. This is because mammals, unlike other groups of vertebrates, have complex social structures and behaviors that often involve the care of offspring by parents. This includes feeding, protection, and teaching of survival skills.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagrams below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Which of the organisms represented are notable agricultural pests?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I is grasshopper; IV is caterpillar. These two are notable agricultural pests. I and IV are grasshopper and caterpillar respectively. Grasshoppers and caterpillars are significant agricultural pests because they: <br/>  <br/> - Destroy crops and cause yield loss <br/> - Have a wide host range and can feed on various crops <br/> - Breed rapidly and migrate, spreading damage <br/> - Can be difficult to detect and control <br/> - Can cause significant economic losses for farmers <br/>  <br/> These characteristics make them notable pests in agricultural settings.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagrams below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> An economic importance of the organism represented by IV is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it transmits water-bore disease to humans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is destructive to farm crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its faeces pollutes drinking water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It helps in the control of mosquito larvae</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An economic importance of the organism represented by IV is that it is destructive to farm crops. Because it feeds on plant crops.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The adaptive importance of nuptial flight from termite colonies is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">disperse the reproductive in order to establish new colonies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide abundant food for birds and other animals during the early rains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure cross-breeding between members of one colony and another</div>", "<div style=\"font-family:Cambria;font-size:17px;\">expel the reproductive so as to provide enough food for other members</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The adaptive importance of nuptial flight from termite colonies is to disperse the reproductive in order to establish new colonies. This is a form of reproduction strategy where the reproductive termites, also known as alates, fly out of their original colonies to mate and establish new colonies. This helps in the survival and spread of the termite species.</div>", "topic": "ADAPTATION FOR SURVIVAL : COMPETITION"}, {"id": "objective>Biology>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The gas evolved in the process is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (II) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lime water is used to test for presence of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/> The gas evolved is likely carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). Here's why: <br/>  <br/> 1. Lime water (calcium hydroxide, Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) is a strong base. <br/> 2. When CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is bubbled through lime water, it reacts with the calcium hydroxide to form calcium carbonate (CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>), a white precipitate. <br/>  <br/> Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (lime water) + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> (white precipitate) + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O <br/>  <br/> The formation of the white precipitate (calcium carbonate) is what turns the lime water milky. <br/>  <br/> Other gases, like oxygen, nitrogen, or hydrogen, wouldn't produce this characteristic milky appearance with lime water. Therefore, the gas evolved is likely carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). <br/> </div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The experimental set-up above is used to demonstrate the process of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">photosynthesis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fermentation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">plasmolysis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The experimental set-up above is used to demonstrate the process of fermentation. Sucrose ferments to yield CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.</div>", "topic": "NUTRITION : PHOTOSYNTHESIS"}, {"id": "objective>Biology>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following can cause shrinkage of living cells?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hypotonic solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Isotonic solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deionized water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hypertonic solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hypertonic solution can cause shrinkage of living cells. This is because a hypertonic solution has a higher concentration of solutes outside the cell than inside. As a result, water moves out of the cell through osmosis to balance the concentration of solutes, causing the cell to shrink. This process is known as plasmolysis.</div>", "topic": "COORDINATION AND CONTROL : HOMEOSTASIS"}, {"id": "objective>Biology>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is true of leucocytes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They are respiratory pigments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are most numerous and ramify all cells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are large and nucleated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are involved in blood clotting</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Leucocytes, also known as white blood cells, are large and nucleated. They play an important role in the body's immune system, helping to fight off infections. They are not involved in blood clotting (that's the role of platelets), they are not respiratory pigments (that's the role of hemoglobin in red blood cells), and they are not the most numerous cells in the body (that would be red blood cells).</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of a nutrient into a molecule in the body of a consumer is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">digestion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">assimilation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorption </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inhibition</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conversion of a nutrient into a molecule in the body of a consumer is referred to as assimilation. This is the process by which the body uses the nutrients absorbed from the digestive tract to produce the molecules it needs for energy, growth, and cell repair. Digestion is the breakdown of food into smaller components that can be absorbed, absorption is the process of taking these components into the body's internal environment, and inhibition is not related to this process.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of a living organism to detect and respond to changes in the environment is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">locomotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">irritability</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">taxis</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ability of a living organism to detect and respond to changes in the environment is referred to as irritability. This is a fundamental property of living organisms, allowing them to adapt to changing conditions. Locomotion is movement, growth is an increase in size or number of cells, and taxis is a directed movement towards or away from a stimulus.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the exchange of nutrients and metabolic products occurs in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lungs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oesophagus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lymph</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In mammals, the exchange of nutrients and metabolic products occurs in the lymph. The lymphatic system is a network of tissues and organs that help rid the body of toxins, waste and other unwanted materials. The primary function of the lymphatic system is to transport lymph, a fluid containing infection-fighting white blood cells, throughout the body.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of an endospermous seed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maize grain </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cashew nut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cotton seed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bean seed</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An endospermous seed is one in which the endosperm remains in the mature seed and provides nutrition to the developing embryo. Maize grain is an example of an endospermous seed. In contrast, cashew nut, cotton seed, and bean seed are examples of non-endospermous seeds, where the endosperm is completely absorbed by the embryo before seed maturation.</div>", "topic": "GROWTH : GERMINATION OF SEEDS AND CONDITION NECESSARY FOR GERMINATION OF SEEDS"}, {"id": "objective>Biology>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Parasitism Sundew  <br/>  II. Autotrophism Amoeba  <br/>  III. Saprophytism Alga  <br/>  IV Heterotrophism Agama  <br/>  Which of the above modes of nutrition is correctly matched with the organism that exhibits it?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agama cannot manufacture its food. Heterotrophism-Agama </div>", "topic": "NUTRITION : MODES OF NUTRITION"}, {"id": "objective>Biology>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer the question that follows  <br/>  <br/> I. Test tube containing cane sugar and water  <br/> II. Test tube containing cane sugar and dilute acid  <br/> III. Test tube containing cane sugar and its degrading enzyme <br/>  <br/> In which of the test tubes will glucose be detected after complete hydrolysis?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrolysis is a chemical reaction in which water is used to break down a compound. This process can be catalyzed by acids, enzymes or heat. In the given options, test tube II contains cane sugar and dilute acid, and test tube III contains cane sugar and its degrading enzyme. Both these conditions will facilitate the hydrolysis of cane sugar into glucose. Hence, glucose will be detected in both these test tubes after complete hydrolysis.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer the question that follows  <br/>  <br/> I. Test tube containing cane sugar and water  <br/> II. Test tube containing cane sugar and dilute acid  <br/> III. Test tube containing cane sugar and its degrading enzyme  <br/>  <br/> The enzyme involved in the hydrolysis is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rennin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">erepsin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sucrase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maltase</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sucrase is the enzyme that catalyzes the hydrolysis of sucrose (cane sugar) to fructose and glucose. Rennin is an enzyme found in the stomach of young mammals that curdles milk, erepsin is an enzyme that breaks down peptones into amino acids, and maltase is an enzyme that breaks down maltose into glucose.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the mammalian ear responsible for the maintenance of balance is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cochlea </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pinna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perilymph </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vestibular system</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cochlea is a part of the inner ear in mammals that is responsible for hearing. However, the maintenance of balance is not done by the cochlea but by the vestibular system, which includes the semicircular canals and the otolith organs (the utricle and the saccule). </div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The path followed by air as it passes through the lungs in mammals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">trachea → bronchi → bronchioles → alveoli</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bronchi → trachea → alveoli → bronchioles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trachea → bronchioles → bronchi → alveoli.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bronchioles → alveoli → bronchi → trachea.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The path of air as it passes through the lungs in mammals is as follows: it enters through the trachea, then moves to the bronchi, then to the bronchioles, and finally to the alveoli where gas exchange occurs. This is the correct path of air flow in the respiratory system of mammals.</div>", "topic": "RESPIRATION : RESPIRATORY ORGANS AND SURFACES"}, {"id": "objective>Biology>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The movement response of a cockroach away from a light source can be described as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">positive phototaxism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative phototaxism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative phototropism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive phototropism</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The movement of a cockroach away from a light source is described as negative phototaxis. Phototaxis is the movement of an organism in response to light: positive phototaxis is movement towards light, while negative phototaxis is movement away from light. Therefore, since the cockroach is moving away from the light source, it is exhibiting negative phototaxis.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vascular tissues in higher plants are responsible for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the movement of food and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">suction pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transpiration pull</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the transport of gases and water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vascular tissues in higher plants, which include the xylem and phloem, are responsible for the movement of food and water. The xylem transports water and minerals from the roots to the rest of the plant, while the phloem transports food (sugars) from the leaves to the rest of the plant. Therefore, the correct answer is that the vascular tissues are responsible for the movement of food and water.</div>", "topic": "TRANSPORT : PLANT VASCULAR SYSTEM"}, {"id": "objective>Biology>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following organs regulates the levels of water, salts, hydrogen ions and urea in the mammalian blood?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Liver </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kidney</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bladder </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Colon</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The kidney is the organ that regulates the levels of water, salts, hydrogen ions and urea in the mammalian blood. It does this through the process of filtration, reabsorption, and secretion. Filtration removes waste products and excess substances from the blood. Reabsorption returns needed substances from the filtrate back into the blood. Secretion removes additional wastes from the blood into the filtrate.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of the one-way gaseous exchange mechanism in a fish is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">operculum → gills → mouth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gills → operculum → mouth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mouth → operculum → gills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mouth → gills → operculum.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sequence of the one-way gaseous exchange mechanism in a fish is mouth → gills → operculum. Water (carrying dissolved oxygen) enters the fish's mouth and flows over the gills. At the gills, oxygen is transferred from the water into the fish's blood, and carbon dioxide (a waste product) is transferred from the fish's blood into the water. The water then exits the fish through the operculum.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of asexual reproduction that is common to both Paramecium and Protists is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">budding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sporulation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fragmentation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fission</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of asexual reproduction that is common to both Paramecium and Protists is fission. Fission is a form of asexual reproduction in which an organism divides into two or more equal or nearly equal parts. In the case of Paramecium and Protists, this is usually binary fission, where the organism splits into two.</div>", "topic": "REPRODUCTION : ASEXUAL REPRODUCTION"}, {"id": "objective>Biology>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In nature, plants and animals are perpetually engaged in mutualism because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">they are rivals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all animals rely on food produced by plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they utilize respiratory wastes of each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are neighbours</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mutualism is a type of symbiotic relationship where both organisms benefit. In this case, plants and animals are engaged in mutualism because they utilize each other's respiratory wastes. Plants take in carbon dioxide, which is a waste product of animal respiration, and release oxygen, which is a waste product of plant photosynthesis and a necessary component for animal respiration.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to determine the percentage of humus and water in a soil <br/> sample, the following results were obtained.  <br/>  Weight of the evaporating basin alone = 80.5g  <br/>  Weight of basin and soil = 101.5g  <br/>  Weight after dying the soil in the oven = 99.0g  <br/>  Weight of basin and roasted soil = 95.5g.  <br/>  The percentage of humus in the soil sample is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">16.7% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">17.6%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26.7% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.2%.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The weight of the soil is 101.5g - 80.5g = 21g. The weight of the soil after drying is 99.0g - 80.5g = 18.5g. The weight of the soil after roasting is 95.5g - 80.5g = 15g. The weight of the humus is the weight of the soil after drying minus the weight of the soil after roasting, which is 18.5g - 15g = 3.5g. The percentage of humus in the soil sample is (3.5g / 21g) * 100% = 16.7%. <br/> Mass of soil = 101.5 - 80.5 = 21.0g <br/> Mass of humus = 99.0 - 95.5 = 3.5g <br/> % of humus =3.5/21 * 100= 16.7%</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a filter-feeding animal is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shark </div>", "<div style=\"font-family:Cambria;font-size:17px;\">butterfly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mosquito</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Filter-feeding is a method of feeding where the animal filters out tiny organisms or particles floating in water or air. An example of a filter-feeding animal is a whale. Whales are known to filter-feed on tiny organisms like krill and plankton.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a feature of the population pyramid of a developing country?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Long life span </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">short lifespan</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A population pyramid of a developing country is typically characterized by a broad base and a narrow top, indicating a high birth rate and a short lifespan. This is due to factors such as lower healthcare standards, higher child mortality, and other socio-economic factors.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The interaction of a community of organisms with its abiotic environment constitutes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a niche </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a food chain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an ecosystem </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a microhabitat</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ecosystem is a community of living organisms in conjunction with the nonliving components of their environment, interacting as a system. These biotic and abiotic components are linked together through nutrient cycles and energy flows.</div>", "topic": "ECOLOGY : SYMBIOTIC INTERACTIONS OF PLANTS AND ANIMALS"}, {"id": "objective>Biology>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The vector of the malaria parasite is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">female Aedes mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female Anopheles mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male Culex mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">female Culex mosquito</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The vector of the malaria parasite is the female Anopheles mosquito. The female mosquito is the one that bites and transmits the disease because it needs blood for its eggs to develop. The Anopheles mosquito is the specific species that carries the malaria parasite.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following instruments is used to measure relative humidity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hydrometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thermometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hygrometer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anemometer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A hygrometer is an instrument used to measure the amount of humidity and water vapor in the atmosphere, in soil, or in confined spaces. Humidity measurement instruments usually rely on measurements of some other quantity such as temperature, pressure, mass, a mechanical or electrical change in a substance as moisture is absorbed.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Exo-erythrocytic phase of the life cycle of malaria parasite occurs in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Liver of humans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reticuloendothelial cells of humans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malpighian tubules of mosquito</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brain of humans</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The exo-erythrocytic phase of the life cycle of the malaria parasite occurs in the liver of humans. This is the phase where the parasite infects the liver cells and multiplies within them. After a period of time, the infected liver cells burst, releasing thousands of parasites into the bloodstream, where they invade red blood cells and multiply further.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Habitats are generally classified into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">biotic and abiotic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aquatic and terrestrial</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aboreal and marine biomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microhabitats and microhabitats</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Habitats are generally classified into aquatic and terrestrial. Aquatic habitats are those that are water-based, such as oceans, rivers, and lakes. Terrestrial habitats are those that are land-based, such as forests, deserts, and grasslands. These two broad categories can be further divided into more specific types of habitats.</div>", "topic": "NATURAL HABITAT : AQUATIC TERRESTRIAL AND ARBOREAL"}, {"id": "objective>Biology>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Dracunculiasis can be contacted through</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eating contaminated food</div>", "<div style=\"font-family:Cambria;font-size:17px;\">drinking contaminated water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bathing in contaminated water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bites of blackfly</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dracunculiasis, also known as Guinea worm disease, is caused by the large female of the nematode <span style=\"font-style:italic;\"> Dracunculus medinensis </span>, which emerges painfully and slowly from the skin, usually on the lower limbs. The disease is contracted when people consume water from stagnant sources contaminated with Guinea worm larvae. Therefore, the correct answer is 'drinking contaminated water'.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups of environmental factors are density dependent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Food, salinity, accumulation of metabolites and light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature, salinity, predation and disease</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Food, predation, disease and accumulation of metabolites</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Temperature, food, disease and light</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Density-dependent factors are factors where the effects on the size or growth of a population vary with the density of the population itself. These include competition, predation, disease and food supply. Therefore, the correct answer is 'Food, predation, disease and accumulation of metabolites'.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Millet, sorghum, maize and onions are common crops grown in Nigeria in the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical rain forests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sudan savanna</div>", "<div style=\"font-family:Cambria;font-size:17px;\">montane forests</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahel savanna</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Millet, sorghum, maize and onions are common crops grown in the Sudan savanna region of Nigeria. The Sudan savanna is a kind of savanna (a mixed woodland-grassland ecosystem characterized by the trees being sufficiently widely spaced so that the canopy does not close) that is similar to the Sahel, but the Sudan savanna has more rainfall. Therefore, the correct answer is 'Sudan savanna'.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : SUDAN SAVANNA"}, {"id": "objective>Biology>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following biomes is the south western part of Nigeria located?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Temperature forest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical woodland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Desert</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The south western part of Nigeria is located in the Tropical rain forest biome. This biome is characterized by high rainfall and temperatures, and it's the most biodiverse biome on earth. The other options are incorrect because they do not accurately describe the climate and ecological characteristics of south western Nigeria.</div>", "topic": "LOCAL(NIGERIAN) BIOMES : TROPICAL RAINFOREST"}, {"id": "objective>Biology>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lack of space in a population could lead to an increase in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water scarcity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">birth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disease rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">drought</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lack of space in a population could lead to an increase in disease rate. This is because when individuals are in close proximity to each other, the likelihood of disease transmission increases. Water scarcity and drought are related to environmental conditions, not population density. An increase in birth rate is unlikely because lack of space generally leads to increased competition for resources, which can actually decrease birth rates.</div>", "topic": "THE ECOLOGY OF POPULATIONS : FACTORS AFFECTING POPULATION SIZES"}, {"id": "objective>Biology>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The inheritable characters that are determined by a gene located only on the X chromosome is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">recessive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sex-linked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">homozygous </div>", "<div style=\"font-family:Cambria;font-size:17px;\">dominant</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The inheritable characters that are determined by a gene located only on the X chromosome are sex-linked. Sex-linked traits are associated with genes found on sex chromosomes. In humans, the term generally refers to traits that are influenced by genes on the X chromosome. This is because the X chromosome is large and contains many more genes than the smaller Y chromosome. Recessive, homozygous, and dominant are terms used to describe the expression of traits, not their location on chromosomes.</div>", "topic": "HEREDITY : SEX-LINKED CHARACTERS"}, {"id": "objective>Biology>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the cross of a red-flowered plant with a white-flowered plant produces a pink-flowered plant, it is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">codominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">incomplete dominance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linkage</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon described in the question is an example of incomplete dominance. Incomplete dominance is a form of intermediate inheritance in which one allele for a specific trait is not completely expressed over its paired allele. This results in a third phenotype in which the expressed physical trait is a combination of the phenotypes of both alleles. In this case, neither the red nor the white trait is dominant, so the resulting flower is pink.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following theories was NOT considered by Darwin in his evolutionary <br/> theory?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Survival of the fittest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use and disuse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Competition</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of 'Use and disuse' was not considered by Darwin in his evolutionary theory. This theory, proposed by Jean-Baptiste Lamarck, suggests that an organism can change during its lifetime in response to its environment, and those changes are then passed onto its offspring. Darwin's theory of evolution, on the other hand, is based on natural selection, or the survival of the fittest, where traits beneficial for survival are passed onto the next generation.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The crossing of individuals of the same species with different genetic characters is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cross breeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polygenic inheritance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-disjunction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inbreeding</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The crossing of individuals of the same species with different genetic characters is known as cross breeding. Cross breeding is a method used to improve the genetic characteristics of offspring by mating two individuals with different traits. This is done to combine the desirable traits of the parents in the offspring.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of alleles controlling blood groups in humans is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The human blood group system (ABO) is controlled by three alleles: IA, IB, and i. IA and IB are co-dominant, meaning that they both express themselves when present. The i allele is recessive to both IA and IB. Therefore, the number of alleles controlling blood groups in humans is 3.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During blood transfusion, agglutination may occur as a result of the reaction between</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contrasting antigens and antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different antigens</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different antibodies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">similar antigens and antibodies.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Agglutination during blood transfusion occurs as a result of the reaction between contrasting antigens and antibodies. If the recipient's antibodies bind to the donor's antigens, it causes the red blood cells to clump together, or agglutinate. This can be fatal, as it can block blood vessels and cause harmful reactions.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fallacy in Lamarck's evolutionary theory was the assumption that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">traits are acquired through disuse of body parts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acquired traits are heritable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acquired traits are seldom formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">traits are acquired through the use of body parts</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lamarck's theory of evolution, also known as Lamarckism, proposed that an organism can change during its lifetime in response to its environment, and those changes are inheritable. This is known as the inheritance of acquired characteristics. However, this aspect of Lamarck's theory was disproven with the advent of genetics. We now know that acquired traits, such as muscle mass gained from exercise, cannot be passed on to offspring.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The brightly coloured eye spots on the hind wings of a moth are an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">warning colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">disruptive colouration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crypsis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mimicry</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The brightly coloured eye spots on the hind wings of a moth are an example of warning colouration. Warning colouration, also known as aposematism, is a strategy used by certain animals to warn predators that they are toxic, venomous, or otherwise harmful. The bright colours serve as a deterrent to predators.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The wings of a bat and those of a bird are examples of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convergent evolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coevolution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continuous variation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">divergent evolution</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wings of a bat and those of a bird are examples of convergent evolution. Convergent evolution is the process whereby organisms not closely related (not monophyletic), independently evolve similar traits as a result of having to adapt to similar environments or ecological niches.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A tall plant crossed with a dwarf one produces offspring of which half are tall and half are dwarf. What are the genotypes of the parents?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tt, tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">TT, tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tt, Tt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">TT, TT</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When crossed, it gives half tall and short offspring. <img src=\"2011/k4.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}];
